targets.expr:
count by (namespace, clusterName) (
  (
    kube_pod_labels{label_cnpg_io_cluster=~".*"}
    or
    mongodb_info
    or
    kube_secret_owner{owner_kind="ObjectBucketClaim"}
    or
    kube_persistentvolumeclaim_info
    or
    label_replace(strimzi_resources{kind="Kafka"}, "namespace", "$1", "exported_namespace", "(.*)")
    or
    label_replace(secretstore_status_condition, "namespace", "$1", "exported_namespace", "(.*)")
  )
  * on(namespace, clusterName) group_left(label_apc_namespace_type) kube_namespace_labels{label_apc_namespace_type="application"}
)
